@app.route('/cache/get/<key>', methods=['GET'])
def get_cache_key(key):
    value = memcache_client.get(key)
    if value is not None:
        return jsonify({
            'key': key,
            'value': value,
            'found': True
        })
    return jsonify({
        'key': key,
        'found': False
    }), 404

@app.route('/cache/set', methods=['POST'])
def set_cache_key():
    data = request.get_json()
    key = data.get('key')
    value = data.get('value')
    ttl = data.get('ttl', 300)
    
    if not key or value is None:
        return jsonify({'error': 'Key and value are required'}), 400
    
    memcache_client.set(key, value, expire=ttl)
    return jsonify({
        'message': 'Cache key set successfully',
        'key': key,
        'ttl': ttl
    })

@app.route('/cache/delete/<key>', methods=['DELETE'])
def delete_cache_key(key):
    result = memcache_client.delete(key)
    return jsonify({
        'message': 'Cache key deleted' if result else 'Cache key not found',
        'key': key,
        'deleted': bool(result)
    })

@app.route('/health', methods=['GET'])
def health():
    try:
        memcache_client.set('health_check', 'ok', expire=10)
        cache_status = memcache_client.get('health_check') == 'ok'
    except:
        cache_status = False
    
    try:
        conn = get_db()
        conn.close()
        db_status = True
    except:
        db_status = False
    
    return jsonify({
        'status': 'healthy' if (cache_status and db_status) else 'unhealthy',
        'cache': 'connected' if cache_status else 'disconnected',
        'database': 'connected' if db_status else 'disconnected'
    })

